const homepageStyles = "@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');\n/* ---------------- TOKENS ---------------- */\r\n  :root {\r\n    --green: #4ea84e;            /* brand accent green */\r\n    --green-bright: #5cb55c;\r\n    --green-dark: #163d2a;       /* deep forest green */\r\n    --green-darker: #0f2e20;\r\n    --green-soft: #e8f3e6;\r\n    --cream: #f5efdf;\r\n    --cream-2: #efe9d7;\r\n    --bg: #ffffff;\r\n    --gray-50: #f7f6f3;\r\n    --gray-100: #f1efea;\r\n    --gray-200: #e6e3dc;\r\n    --gray-300: #d9d5cc;\r\n    --text: #1a1a1a;\r\n    --text-muted: #6b7280;\r\n    --border: #e7e4dc;\r\n    --radius: 10px;\r\n    --radius-lg: 16px;\r\n    --shadow-sm: 0 2px 6px rgba(0,0,0,0.04);\r\n    --shadow-md: 0 6px 24px rgba(0,0,0,0.08);\r\n    --shadow-lg: 0 20px 50px rgba(0,0,0,0.15);\r\n    --maxw: 1180px;\r\n  }\r\n\r\n  /* ---------------- RESET ---------------- */\r\n  *, *::before, *::after { box-sizing: border-box; }\r\n  html { -webkit-text-size-adjust: 100%; }\r\n  body {\r\n    margin: 0;\r\n    font-family: 'Inter', -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, sans-serif;\r\n    color: var(--text);\r\n    background: #fff;\r\n    line-height: 1.55;\r\n    -webkit-font-smoothing: antialiased;\r\n    font-size: 16px;\r\n  }\r\n  img { max-width: 100%; display: block; }\r\n  a { color: inherit; text-decoration: none; }\r\n  button { font-family: inherit; cursor: pointer; border: 0; background: none; }\r\n  h1, h2, h3, h4, h5 { margin: 0; line-height: 1.15; letter-spacing: -0.01em; font-weight: 700; }\r\n  p { margin: 0; }\r\n\r\n  .wrap { max-width: var(--maxw); margin: 0 auto; padding: 0 28px; }\r\n  .green { color: var(--green); }\r\n  .eyebrow {\r\n    color: var(--green);\r\n    font-weight: 700;\r\n    font-size: 0.78rem;\r\n    letter-spacing: 0.18em;\r\n    text-transform: uppercase;\r\n  }\r\n\r\n  /* ---------------- BUTTONS ---------------- */\r\n  .btn {\r\n    display: inline-flex; align-items: center; justify-content: center;\r\n    padding: 13px 22px;\r\n    border-radius: 8px;\r\n    font-weight: 600;\r\n    font-size: 0.95rem;\r\n    transition: transform 0.15s ease, box-shadow 0.15s ease, background 0.15s ease;\r\n    white-space: nowrap;\r\n  }\r\n  .btn-primary { background: var(--green); color: #fff; box-shadow: 0 2px 8px rgba(78,168,78,0.3); }\r\n  .btn-primary:hover { background: #449e44; transform: translateY(-1px); }\r\n  .btn-outline { background: #fff; color: var(--text); border: 1.5px solid var(--text); }\r\n  .btn-outline:hover { background: var(--text); color: #fff; }\r\n  .btn-outline-light { background: transparent; color: var(--text); border: 1.5px solid var(--gray-300); }\r\n  .btn-outline-light:hover { background: var(--text); color: #fff; border-color: var(--text); }\r\n  .btn-sm { padding: 10px 18px; font-size: 0.9rem; }\r\n\r\n  /* ---------------- HEADER / NAV ---------------- */\r\n  .nav {\r\n    position: sticky; top: 0; z-index: 50;\r\n    background: rgba(255,255,255,0.95);\r\n    backdrop-filter: blur(8px);\r\n    border-bottom: 1px solid rgba(0,0,0,0.03);\r\n  }\r\n  .nav-inner {\r\n    display: flex; align-items: center; justify-content: space-between;\r\n    height: 72px;\r\n  }\r\n  .logo { display: flex; align-items: center; gap: 10px; }\r\n  .logo-mark {\r\n    width: 38px; height: 38px;\r\n    display: flex; align-items: center; justify-content: center;\r\n    color: var(--green);\r\n  }\r\n  .logo-text {\r\n    display: flex; flex-direction: column; line-height: 1;\r\n  }\r\n  .logo-text .pro {\r\n    font-weight: 800; font-size: 1.25rem; letter-spacing: 0.02em;\r\n    color: var(--green-dark);\r\n  }\r\n  .logo-text .pro em { font-style: normal; color: var(--green); }\r\n  .logo-text .crm {\r\n    font-size: 0.68rem; letter-spacing: 0.5em; color: var(--green-dark);\r\n    margin-top: 4px; padding-top: 4px; border-top: 1px solid var(--green-dark);\r\n    font-weight: 600;\r\n  }\r\n  .nav-links {\r\n    display: flex; align-items: center; gap: 30px;\r\n    font-weight: 500; font-size: 0.95rem; color: var(--text);\r\n  }\r\n  .nav-links a { display: inline-flex; align-items: center; gap: 4px; }\r\n  .nav-links a:hover { color: var(--green); }\r\n  .nav-right { display: flex; align-items: center; gap: 18px; }\r\n  .nav-right .login { font-weight: 500; font-size: 0.95rem; }\r\n  .nav-right .login:hover { color: var(--green); }\r\n\r\n  /* ---------------- HERO ---------------- */\r\n  .hero {\r\n    position: relative;\r\n    overflow: hidden;\r\n    padding: 70px 0 80px;\r\n    background:\r\n      radial-gradient(ellipse at 80% 20%, rgba(255, 240, 200, 0.6) 0%, transparent 50%),\r\n      radial-gradient(ellipse at 10% 80%, rgba(120, 180, 100, 0.25) 0%, transparent 60%),\r\n      linear-gradient(180deg, #f0e9d4 0%, #d8e3c4 35%, #b9d098 70%, #8ab86e 100%);\r\n  }\r\n  .hero::before {\r\n    /* Subtle house silhouette top-right */\r\n    content: \"\";\r\n    position: absolute;\r\n    top: 30px; right: 4%;\r\n    width: 360px; height: 200px;\r\n    background:\r\n      linear-gradient(180deg, transparent 35%, rgba(70, 60, 50, 0.18) 35%, rgba(80, 70, 60, 0.15) 60%, transparent 60%);\r\n    clip-path: polygon(20% 100%, 20% 50%, 50% 20%, 80% 50%, 80% 100%);\r\n    opacity: 0.7;\r\n    pointer-events: none;\r\n    filter: blur(0.5px);\r\n  }\r\n  .hero::after {\r\n    /* Foliage row at bottom of hero */\r\n    content: \"\";\r\n    position: absolute;\r\n    left: 0; right: 0; bottom: 0;\r\n    height: 110px;\r\n    background:\r\n      radial-gradient(ellipse 100px 70px at 5% 80%, #3b6d3b 0%, transparent 70%),\r\n      radial-gradient(ellipse 120px 85px at 18% 75%, #4a7a3a 0%, transparent 70%),\r\n      radial-gradient(ellipse 110px 70px at 28% 82%, #3d6d3d 0%, transparent 70%),\r\n      radial-gradient(ellipse 130px 90px at 42% 75%, #4e8245 0%, transparent 70%),\r\n      radial-gradient(ellipse 100px 70px at 58% 82%, #3b6d3b 0%, transparent 70%),\r\n      radial-gradient(ellipse 130px 80px at 72% 75%, #4a7a3a 0%, transparent 70%),\r\n      radial-gradient(ellipse 110px 75px at 88% 80%, #3d6d3d 0%, transparent 70%);\r\n    pointer-events: none;\r\n  }\r\n  .hero-inner {\r\n    position: relative; z-index: 2;\r\n    display: grid; grid-template-columns: 1.05fr 1.2fr; gap: 40px; align-items: center;\r\n  }\r\n  .hero h1 {\r\n    font-size: clamp(2.4rem, 4.6vw, 3.7rem);\r\n    font-weight: 700;\r\n    color: #18221a;\r\n    margin-bottom: 22px;\r\n  }\r\n  .hero h1 .accent { color: var(--green); }\r\n  .hero p.lede {\r\n    font-size: 1.05rem;\r\n    color: #2a3a30;\r\n    max-width: 480px;\r\n    margin-bottom: 28px;\r\n  }\r\n  .hero-cta { display: flex; gap: 14px; margin-bottom: 18px; }\r\n  .hero-check-row {\r\n    display: flex; gap: 22px; color: #2a3a30; font-size: 0.92rem; font-weight: 500;\r\n  }\r\n  .hero-check-row span {\r\n    display: inline-flex; align-items: center; gap: 6px;\r\n  }\r\n  .hero-check-row svg { color: var(--green); flex-shrink: 0; }\r\n\r\n  /* ---------- Dashboard mockup ---------- */\r\n  .device-stage { position: relative; height: 510px; }\r\n  .tablet {\r\n    position: absolute; top: 0; left: 30px;\r\n    width: 580px; height: 410px;\r\n    background: #1c1c1c;\r\n    border-radius: 18px;\r\n    padding: 10px;\r\n    box-shadow: var(--shadow-lg);\r\n  }\r\n  .tablet-screen {\r\n    width: 100%; height: 100%;\r\n    background: #fff;\r\n    border-radius: 8px;\r\n    overflow: hidden;\r\n    display: grid;\r\n    grid-template-columns: 130px 1fr;\r\n  }\r\n  .dash-side {\r\n    background: var(--green-dark);\r\n    color: #fff;\r\n    padding: 14px 10px;\r\n    font-size: 11px;\r\n  }\r\n  .dash-side .mini-logo {\r\n    display: flex; align-items: center; gap: 6px; padding: 4px 8px; margin-bottom: 14px;\r\n  }\r\n  .dash-side .mini-logo .mark { width: 18px; height: 18px; color: var(--green); }\r\n  .dash-side .mini-logo .label { font-size: 9px; font-weight: 800; letter-spacing: 0.04em; }\r\n  .dash-side .mini-logo .label small { display: block; font-size: 6px; letter-spacing: 0.4em; opacity: 0.7; margin-top: 1px; }\r\n  .dash-side nav { display: flex; flex-direction: column; gap: 2px; }\r\n  .dash-side a {\r\n    display: flex; align-items: center; gap: 7px;\r\n    padding: 6px 8px; border-radius: 5px;\r\n    color: rgba(255,255,255,0.78);\r\n    font-size: 10.5px;\r\n  }\r\n  .dash-side a.active { background: rgba(255,255,255,0.12); color: #fff; }\r\n  .dash-side a svg { width: 12px; height: 12px; }\r\n\r\n  .dash-main { padding: 12px 14px; overflow: hidden; }\r\n  .dash-title { font-size: 1rem; font-weight: 700; margin-bottom: 10px; }\r\n  .dash-stats { display: grid; grid-template-columns: repeat(4, 1fr); gap: 8px; margin-bottom: 12px; }\r\n  .dash-stat {\r\n    border: 1px solid var(--border);\r\n    border-radius: 6px;\r\n    padding: 8px 9px;\r\n  }\r\n  .dash-stat .label { font-size: 7px; letter-spacing: 0.12em; color: var(--text-muted); font-weight: 600; }\r\n  .dash-stat .num { font-size: 1.15rem; font-weight: 700; margin-top: 2px; }\r\n  .dash-stat .num.warn { color: #d4842a; }\r\n  .dash-stat .link { font-size: 7.5px; color: var(--green); margin-top: 2px; font-weight: 600; }\r\n\r\n  .dash-charts { display: grid; grid-template-columns: 1fr 1fr; gap: 8px; }\r\n  .dash-panel {\r\n    border: 1px solid var(--border);\r\n    border-radius: 6px;\r\n    padding: 8px;\r\n    background: #fff;\r\n  }\r\n  .dash-panel h4 {\r\n    font-size: 9px; font-weight: 700; margin-bottom: 6px;\r\n    display: flex; justify-content: space-between; align-items: center;\r\n    color: var(--text);\r\n  }\r\n  .dash-panel h4 .meta { font-size: 7px; font-weight: 500; color: var(--text-muted); }\r\n  .dash-map {\r\n    height: 90px; border-radius: 4px;\r\n    background:\r\n      linear-gradient(135deg, #e8f0e0 0%, #d8e6cc 100%);\r\n    position: relative; overflow: hidden;\r\n    margin-bottom: 6px;\r\n  }\r\n  .dash-map svg { width: 100%; height: 100%; }\r\n  .dash-tech-table { width: 100%; font-size: 8px; border-collapse: collapse; }\r\n  .dash-tech-table th { text-align: left; padding: 2px 4px; color: var(--text-muted); font-weight: 600; font-size: 7px; }\r\n  .dash-tech-table td { padding: 2px 4px; border-top: 1px solid var(--border); }\r\n  .dash-tech-table .dot { width: 6px; height: 6px; border-radius: 50%; display: inline-block; margin-right: 4px; vertical-align: middle; }\r\n\r\n  .dash-line-chart { height: 90px; position: relative; margin-bottom: 6px; }\r\n  .dash-line-chart svg { width: 100%; height: 100%; }\r\n  .chart-yaxis { position: absolute; left: 0; top: 0; bottom: 0; display: flex; flex-direction: column; justify-content: space-between; font-size: 6px; color: var(--text-muted); padding: 2px 0; }\r\n  .chart-xaxis { display: flex; justify-content: space-between; font-size: 6.5px; color: var(--text-muted); padding-left: 20px; }\r\n  .dash-donut-row { display: flex; gap: 8px; align-items: center; margin-top: 6px; }\r\n  .dash-donut { width: 50px; height: 50px; flex-shrink: 0; }\r\n  .dash-legend { font-size: 7px; }\r\n  .dash-legend div { display: flex; align-items: center; gap: 4px; padding: 1px 0; }\r\n  .dash-legend .dot { width: 6px; height: 6px; border-radius: 50%; display: inline-block; }\r\n\r\n  .phone {\r\n    position: absolute; right: -10px; bottom: 0;\r\n    width: 175px; height: 350px;\r\n    background: #1c1c1c;\r\n    border-radius: 22px;\r\n    padding: 8px;\r\n    box-shadow: var(--shadow-lg);\r\n    z-index: 3;\r\n  }\r\n  .phone-screen {\r\n    width: 100%; height: 100%;\r\n    background: #fff;\r\n    border-radius: 16px;\r\n    overflow: hidden;\r\n    display: flex; flex-direction: column;\r\n    padding: 10px 10px 0;\r\n  }\r\n  .phone-screen .greeting { font-size: 11px; font-weight: 700; color: var(--text); }\r\n  .phone-screen .greeting .name { color: var(--green); }\r\n  .phone-screen .date { font-size: 7.5px; color: var(--text-muted); margin-bottom: 6px; }\r\n  .phone-screen h5 { font-size: 9px; font-weight: 700; margin: 4px 0 4px; }\r\n  .phone-jobs { display: flex; flex-direction: column; gap: 4px; flex: 1; }\r\n  .phone-job {\r\n    display: grid; grid-template-columns: 32px 1fr;\r\n    gap: 6px; padding: 4px 6px;\r\n    background: var(--green-soft);\r\n    border-radius: 5px;\r\n    font-size: 7.5px;\r\n  }\r\n  .phone-job .time { font-weight: 700; color: var(--green-dark); line-height: 1.1; font-size: 7px; }\r\n  .phone-job .time small { font-weight: 500; opacity: 0.7; }\r\n  .phone-job .info .addr { font-weight: 600; color: var(--text); }\r\n  .phone-job .info .type { color: var(--text-muted); margin-top: 1px; }\r\n  .phone-tabs { display: flex; justify-content: space-around; padding: 6px 0 6px; border-top: 1px solid var(--border); margin-top: 6px; }\r\n  .phone-tabs div { display: flex; flex-direction: column; align-items: center; gap: 1px; font-size: 6.5px; color: var(--text-muted); }\r\n  .phone-tabs div.active { color: var(--green); }\r\n  .phone-tabs svg { width: 10px; height: 10px; }\r\n\r\n  /* ---------------- TRUST BAR ---------------- */\r\n  .trust-bar {\r\n    background: var(--green-dark);\r\n    color: #fff;\r\n    padding: 28px 0 30px;\r\n  }\r\n  .trust-bar .label {\r\n    text-align: center; font-size: 0.85rem; opacity: 0.85; margin-bottom: 18px; font-weight: 500;\r\n  }\r\n  .logo-row {\r\n    display: flex; justify-content: space-between; align-items: center; gap: 30px;\r\n    flex-wrap: wrap;\r\n  }\r\n  .client-logo {\r\n    display: flex; align-items: center; gap: 8px;\r\n    color: #fff; opacity: 0.92;\r\n  }\r\n  .client-logo svg { color: #fff; flex-shrink: 0; }\r\n  .client-logo .name {\r\n    display: flex; flex-direction: column; line-height: 1; font-size: 0.78rem;\r\n    letter-spacing: 0.18em; font-weight: 700;\r\n  }\r\n  .client-logo .name small {\r\n    font-size: 0.62rem; letter-spacing: 0.22em; font-weight: 500; opacity: 0.85; margin-top: 3px;\r\n  }\r\n\r\n  /* ---------------- SECTION HEAD ---------------- */\r\n  .section-head { text-align: center; max-width: 760px; margin: 0 auto 50px; }\r\n  .section-head h2 {\r\n    font-size: clamp(1.7rem, 3.3vw, 2.4rem);\r\n    margin: 12px 0 14px;\r\n    font-weight: 700;\r\n  }\r\n  .section-head p { color: var(--text-muted); }\r\n\r\n  /* ---------------- TOOLS GRID ---------------- */\r\n  .tools-section { padding: 80px 0 70px; background: #fff; }\r\n  .tools-grid {\r\n    display: grid; grid-template-columns: repeat(5, 1fr);\r\n    border-top: 1px solid var(--border);\r\n  }\r\n  .tool-cell {\r\n    text-align: center;\r\n    padding: 36px 18px 28px;\r\n    border-right: 1px solid var(--border);\r\n  }\r\n  .tool-cell:last-child { border-right: 0; }\r\n  .tool-icon {\r\n    color: var(--green); margin-bottom: 16px; display: inline-flex;\r\n  }\r\n  .tool-cell h3 { font-size: 1.02rem; font-weight: 700; margin-bottom: 10px; }\r\n  .tool-cell p { font-size: 0.88rem; color: var(--text-muted); line-height: 1.55; }\r\n\r\n  /* ---------------- SOLUTIONS ---------------- */\r\n  .solutions {\r\n    background: var(--cream);\r\n    padding: 70px 0 80px;\r\n  }\r\n  .solutions-card {\r\n    background: var(--cream-2);\r\n    border-radius: var(--radius-lg);\r\n    padding: 48px 50px;\r\n    display: grid; grid-template-columns: 0.85fr 1.1fr; gap: 50px; align-items: center;\r\n  }\r\n  .solutions-card h2 {\r\n    font-size: clamp(1.6rem, 3vw, 2.1rem);\r\n    margin: 10px 0 18px;\r\n  }\r\n  .solutions-card p { color: var(--text-muted); margin-bottom: 22px; font-size: 0.96rem; }\r\n  .solutions-list { list-style: none; padding: 0; margin: 0 0 28px; display: flex; flex-direction: column; gap: 10px; }\r\n  .solutions-list li {\r\n    display: flex; align-items: center; gap: 10px;\r\n    font-weight: 500; color: var(--text);\r\n  }\r\n  .solutions-list li svg { color: var(--green); flex-shrink: 0; }\r\n\r\n  .solutions-visual {\r\n    position: relative;\r\n    height: 360px;\r\n    border-radius: var(--radius-lg);\r\n    overflow: hidden;\r\n    background:\r\n      radial-gradient(ellipse at 30% 30%, rgba(255,235,180,0.4) 0%, transparent 60%),\r\n      linear-gradient(180deg, #c5d9a0 0%, #88b370 40%, #5a8c4a 80%, #3d6e34 100%);\r\n  }\r\n  .solutions-visual::before {\r\n    /* path */\r\n    content: \"\";\r\n    position: absolute;\r\n    bottom: 0; left: 30%;\r\n    width: 40%; height: 70%;\r\n    background: linear-gradient(180deg, transparent 0%, rgba(180, 170, 140, 0.55) 40%, rgba(160, 150, 120, 0.7) 100%);\r\n    transform: perspective(400px) rotateX(60deg);\r\n    transform-origin: bottom center;\r\n    border-radius: 50% 50% 0 0 / 30% 30% 0 0;\r\n  }\r\n  .solutions-visual::after {\r\n    /* house */\r\n    content: \"\";\r\n    position: absolute;\r\n    top: 35%; left: 38%;\r\n    width: 90px; height: 70px;\r\n    background: linear-gradient(180deg, #8c7560 0%, #6e5a48 100%);\r\n    clip-path: polygon(15% 100%, 15% 40%, 50% 10%, 85% 40%, 85% 100%);\r\n  }\r\n  .floating-card {\r\n    position: absolute;\r\n    background: #fff;\r\n    border-radius: 12px;\r\n    padding: 10px 14px;\r\n    display: flex; align-items: center; gap: 10px;\r\n    box-shadow: var(--shadow-md);\r\n    font-size: 0.78rem;\r\n    z-index: 2;\r\n  }\r\n  .floating-card .icon-wrap {\r\n    width: 34px; height: 34px; border-radius: 50%;\r\n    background: var(--green-soft);\r\n    display: flex; align-items: center; justify-content: center;\r\n    color: var(--green);\r\n    flex-shrink: 0;\r\n  }\r\n  .floating-card .title { font-weight: 700; font-size: 0.78rem; }\r\n  .floating-card .sub { color: var(--text-muted); font-size: 0.72rem; margin-top: 1px; }\r\n  .fc-1 { top: 30px; left: 24px; }\r\n  .fc-2 { top: 30px; right: 24px; }\r\n  .fc-3 { bottom: 30px; left: 24px; }\r\n  .fc-4 { bottom: 30px; right: 24px; }\r\n\r\n  .dot-path {\r\n    position: absolute;\r\n    left: 0; right: 0; top: 0; bottom: 0;\r\n    pointer-events: none;\r\n  }\r\n\r\n  /* ---------------- ADVANTAGE ---------------- */\r\n  .advantage {\r\n    background: #fff;\r\n    padding: 60px 0 70px;\r\n  }\r\n  .advantage-inner {\r\n    display: grid; grid-template-columns: 1.2fr 0.8fr; gap: 40px; align-items: center;\r\n  }\r\n  .advantage h2 {\r\n    font-size: clamp(1.4rem, 2.6vw, 1.9rem);\r\n    line-height: 1.25;\r\n  }\r\n  .advantage h2 .green { color: var(--green); }\r\n  .advantage-cta { display: flex; gap: 12px; margin-top: 22px; }\r\n  .advantage-badges {\r\n    display: flex; gap: 30px; justify-content: flex-end;\r\n  }\r\n  .badge {\r\n    display: flex; flex-direction: column; align-items: center; gap: 10px;\r\n    font-weight: 500; font-size: 0.85rem;\r\n  }\r\n  .badge svg { color: var(--green); }\r\n\r\n  /* ---------------- EVERYTHING (6 features) ---------------- */\r\n  .everything { padding: 80px 0 70px; background: #fff; }\r\n  .everything-grid {\r\n    display: grid; grid-template-columns: repeat(6, 1fr);\r\n    border-top: 1px solid var(--border);\r\n  }\r\n  .ev-cell {\r\n    text-align: center;\r\n    padding: 36px 14px 28px;\r\n    border-right: 1px solid var(--border);\r\n  }\r\n  .ev-cell:last-child { border-right: 0; }\r\n  .ev-cell .tool-icon { margin-bottom: 14px; }\r\n  .ev-cell h3 { font-size: 0.95rem; font-weight: 700; margin-bottom: 10px; }\r\n  .ev-cell p { font-size: 0.82rem; color: var(--text-muted); line-height: 1.5; }\r\n\r\n  /* ---------------- INTEGRATIONS ---------------- */\r\n  .integrations {\r\n    padding: 0 0 80px;\r\n    background: #fff;\r\n  }\r\n  .integ-box {\r\n    background: var(--gray-50);\r\n    border-radius: var(--radius-lg);\r\n    padding: 30px 40px 32px;\r\n    text-align: center;\r\n  }\r\n  .integ-box .label { font-weight: 600; margin-bottom: 22px; font-size: 0.98rem; }\r\n  .integ-logos {\r\n    display: flex; justify-content: space-around; align-items: center; gap: 30px; flex-wrap: wrap;\r\n  }\r\n  .integ-logo { font-weight: 700; font-size: 1.15rem; display: flex; align-items: center; gap: 6px; }\r\n  .integ-logo.qb { color: #2ca01c; }\r\n  .integ-logo.qb .lozenge { background: #2ca01c; color: #fff; width: 26px; height: 26px; border-radius: 50%; display: inline-flex; align-items: center; justify-content: center; font-size: 0.9rem; }\r\n  .integ-logo.qb small { font-size: 0.6rem; font-weight: 500; color: var(--text-muted); align-self: flex-start; margin-top: 4px; margin-left: -3px; }\r\n  .integ-logo.stripe { color: #635bff; font-size: 1.55rem; font-style: italic; font-weight: 800; }\r\n  .integ-logo.gcal { display: flex; align-items: center; gap: 8px; color: var(--text); font-weight: 600; font-size: 0.95rem; }\r\n  .integ-logo.gcal .box { width: 26px; height: 26px; background: #fff; border-radius: 4px; display: flex; align-items: center; justify-content: center; font-size: 0.65rem; font-weight: 800; color: #4285f4; border: 1px solid #e0e0e0; box-shadow: 0 1px 2px rgba(0,0,0,0.08); }\r\n  .integ-logo.mailchimp { color: #1a1a1a; font-weight: 600; font-size: 0.98rem; display: flex; align-items: center; gap: 6px; }\r\n  .integ-logo.zapier { color: #ff4f00; font-size: 1.35rem; font-weight: 800; }\r\n  .integ-logo.more { color: var(--text-muted); font-weight: 500; font-size: 0.85rem; max-width: 80px; text-align: left; }\r\n\r\n  /* ---------------- TESTIMONIAL ---------------- */\r\n  .testimonial-section { padding: 0 0 0; background: #fff; }\r\n  .testimonial-card {\r\n    background: var(--cream);\r\n    border-radius: var(--radius-lg);\r\n    padding: 50px 50px;\r\n    display: grid; grid-template-columns: 1fr 0.95fr; gap: 40px; align-items: center;\r\n    overflow: hidden;\r\n    position: relative;\r\n  }\r\n  .testimonial-card h2 {\r\n    font-size: clamp(1.6rem, 3vw, 2.1rem);\r\n    margin-bottom: 22px;\r\n  }\r\n  .quote-mark {\r\n    color: var(--green);\r\n    font-size: 3.2rem;\r\n    line-height: 0.6;\r\n    font-weight: 800;\r\n    margin-bottom: 10px;\r\n    font-family: Georgia, serif;\r\n  }\r\n  .quote-body { font-style: italic; color: #333; font-size: 1.02rem; line-height: 1.6; margin-bottom: 22px; max-width: 440px; }\r\n  .quote-divider { width: 50px; height: 1px; background: var(--text-muted); margin-bottom: 16px; opacity: 0.4; }\r\n  .quote-author { font-size: 1.1rem; font-weight: 700; margin-bottom: 4px; }\r\n  .quote-role { color: var(--green); font-weight: 600; font-size: 0.9rem; margin-bottom: 10px; }\r\n  .stars { display: flex; gap: 4px; color: var(--green); }\r\n  .stats-overlay {\r\n    position: absolute;\r\n    bottom: 30px; left: 47%;\r\n    transform: translateX(-50%);\r\n    background: #fff;\r\n    border-radius: 10px;\r\n    padding: 14px 22px;\r\n    box-shadow: var(--shadow-md);\r\n    display: flex; flex-direction: column; gap: 8px;\r\n    z-index: 3;\r\n    min-width: 310px;\r\n  }\r\n  .stats-overlay .since { font-size: 0.72rem; color: var(--text-muted); font-weight: 500; }\r\n  .stats-overlay .row { display: flex; gap: 24px; align-items: flex-end; justify-content: space-between; }\r\n  .stat-mini { display: flex; flex-direction: column; align-items: center; gap: 2px; }\r\n  .stat-mini .ico { color: var(--green); margin-bottom: 2px; }\r\n  .stat-mini .v { font-size: 1.15rem; font-weight: 700; }\r\n  .stat-mini .l { font-size: 0.7rem; color: var(--text-muted); font-weight: 500; }\r\n\r\n  .testimonial-photo {\r\n    height: 380px;\r\n    border-radius: var(--radius-lg);\r\n    background:\r\n      radial-gradient(ellipse at 70% 30%, rgba(255, 240, 200, 0.4) 0%, transparent 50%),\r\n      linear-gradient(180deg, #d4b896 0%, #a8835f 30%, #5a4030 100%);\r\n    position: relative;\r\n    overflow: hidden;\r\n  }\r\n  .testimonial-photo::before {\r\n    /* shrubs/foliage */\r\n    content: \"\";\r\n    position: absolute;\r\n    bottom: 0; left: 0; right: 0; height: 60%;\r\n    background:\r\n      radial-gradient(ellipse 80px 60px at 20% 80%, #3d5e35 0%, transparent 65%),\r\n      radial-gradient(ellipse 90px 70px at 80% 75%, #4a6d3a 0%, transparent 65%),\r\n      radial-gradient(ellipse 70px 50px at 50% 85%, #3d5e35 0%, transparent 65%);\r\n  }\r\n  .testimonial-person {\r\n    position: absolute;\r\n    top: 12%; left: 50%; transform: translateX(-50%);\r\n    width: 230px; height: 320px;\r\n  }\r\n\r\n  /* ---------------- STATS DARK ---------------- */\r\n  .stats-dark {\r\n    background: var(--green-dark);\r\n    color: #fff;\r\n    padding: 60px 0 70px;\r\n  }\r\n  .stats-dark h2 {\r\n    text-align: center;\r\n    font-size: clamp(1.5rem, 2.6vw, 2rem);\r\n    margin-bottom: 50px;\r\n  }\r\n  .stats-dark h2 .lite { color: #a3d089; }\r\n  .stats-grid {\r\n    display: grid; grid-template-columns: repeat(4, 1fr); gap: 30px;\r\n    text-align: center;\r\n  }\r\n  .stat-big { padding: 0 10px; position: relative; }\r\n  .stat-big::after {\r\n    content: \"\";\r\n    position: absolute;\r\n    right: -15px; top: 30%; bottom: 30%;\r\n    width: 1px;\r\n    background: rgba(255,255,255,0.15);\r\n  }\r\n  .stat-big:last-child::after { display: none; }\r\n  .stat-big .ico { color: #fff; margin-bottom: 14px; display: inline-flex; }\r\n  .stat-big .v { font-size: clamp(1.9rem, 3.5vw, 2.6rem); font-weight: 700; line-height: 1; margin-bottom: 10px; }\r\n  .stat-big .l { font-size: 0.9rem; opacity: 0.92; line-height: 1.4; }\r\n\r\n  /* ---------------- RESOURCES ---------------- */\r\n  .resources { padding: 80px 0 70px; background: #fff; }\r\n  .resources-inner {\r\n    display: grid; grid-template-columns: 0.85fr 2fr; gap: 40px;\r\n  }\r\n  .resources-text h2 { font-size: clamp(1.6rem, 2.8vw, 2.05rem); margin: 14px 0 18px; }\r\n  .resources-text p { color: var(--text-muted); margin-bottom: 22px; }\r\n  .resources-grid {\r\n    display: grid; grid-template-columns: repeat(3, 1fr); gap: 22px;\r\n  }\r\n  .resource-card {\r\n    border-radius: var(--radius);\r\n    overflow: hidden;\r\n    background: #fff;\r\n    display: flex; flex-direction: column;\r\n  }\r\n  .resource-img {\r\n    height: 150px; width: 100%;\r\n    border-radius: var(--radius);\r\n  }\r\n  .resource-img.r1 { background: linear-gradient(135deg, #a8c882 0%, #5e8c45 60%, #3a5e30 100%); position: relative; }\r\n  .resource-img.r2 {\r\n    background: linear-gradient(135deg, #4a6b3d 0%, #2a4030 100%);\r\n    position: relative;\r\n    display: flex; align-items: center; justify-content: center;\r\n  }\r\n  .resource-img.r2::before {\r\n    content: \"\";\r\n    width: 75%; height: 65%;\r\n    background: #f5f5f5;\r\n    border-radius: 6px;\r\n    box-shadow: 0 4px 14px rgba(0,0,0,0.25);\r\n    background-image:\r\n      linear-gradient(180deg, #1a3d2e 0%, #1a3d2e 18%, #fff 18%, #fff 100%),\r\n      linear-gradient(90deg, var(--green) 0%, var(--green) 28%, transparent 28%);\r\n    background-size: 100% 100%, 28% 100%;\r\n    background-repeat: no-repeat, no-repeat;\r\n    background-position: 0 0, 0 100%;\r\n  }\r\n  .resource-img.r3 { background: linear-gradient(135deg, #5e8c45 0%, #3a5e30 50%, #1f3a1f 100%); position: relative; }\r\n  .resource-card .label {\r\n    margin-top: 14px;\r\n    font-size: 0.7rem; letter-spacing: 0.16em; text-transform: uppercase;\r\n    font-weight: 700; color: var(--text-muted);\r\n  }\r\n  .resource-card .title { font-size: 1rem; font-weight: 700; margin: 8px 0 12px; line-height: 1.35; }\r\n  .resource-card .more { color: var(--green); font-weight: 600; font-size: 0.88rem; display: inline-flex; align-items: center; gap: 4px; margin-top: auto; }\r\n\r\n  /* ---------------- CTA BANNER ---------------- */\r\n  .cta-banner { padding: 0 0 70px; background: #fff; }\r\n  .cta-card {\r\n    background: var(--cream);\r\n    border-radius: var(--radius-lg);\r\n    padding: 28px 38px;\r\n    display: flex; align-items: center; gap: 24px;\r\n  }\r\n  .cta-card .leaf-shield {\r\n    width: 56px; height: 64px; flex-shrink: 0;\r\n    background: var(--green);\r\n    clip-path: polygon(50% 0%, 100% 12%, 100% 65%, 50% 100%, 0% 65%, 0% 12%);\r\n    display: flex; align-items: center; justify-content: center;\r\n    color: #fff;\r\n  }\r\n  .cta-card .copy { flex: 1; }\r\n  .cta-card .copy h3 { font-size: 1.3rem; margin-bottom: 6px; }\r\n  .cta-card .copy h3 .green { color: var(--green); }\r\n  .cta-card .copy p { color: var(--text-muted); font-size: 0.92rem; }\r\n  .cta-card .actions { display: flex; gap: 12px; flex-shrink: 0; }\r\n\r\n  /* ---------------- FOOTER ---------------- */\r\n  .footer {\r\n    background: var(--green-darker);\r\n    color: rgba(255,255,255,0.85);\r\n    padding: 50px 0 26px;\r\n    font-size: 0.92rem;\r\n  }\r\n  .footer-grid {\r\n    display: grid; grid-template-columns: 1.6fr 1fr 1fr 1fr 1fr;\r\n    gap: 30px;\r\n    padding-bottom: 30px;\r\n  }\r\n  .footer-brand .logo .pro { color: #fff; }\r\n  .footer-brand .logo .pro em { color: var(--green-bright); }\r\n  .footer-brand .logo .crm { color: #fff; border-color: #fff; }\r\n  .footer-brand .logo .logo-mark { color: var(--green-bright); }\r\n  .footer-brand .tagline {\r\n    margin-top: 18px;\r\n    color: rgba(255,255,255,0.75);\r\n    font-size: 0.85rem;\r\n    line-height: 1.55;\r\n    max-width: 260px;\r\n  }\r\n  .footer-socials {\r\n    display: flex; gap: 12px; margin-top: 18px;\r\n  }\r\n  .footer-socials a {\r\n    width: 30px; height: 30px; border-radius: 50%;\r\n    border: 1px solid rgba(255,255,255,0.35);\r\n    display: inline-flex; align-items: center; justify-content: center;\r\n    color: #fff;\r\n    transition: background 0.15s;\r\n  }\r\n  .footer-socials a:hover { background: var(--green); border-color: var(--green); }\r\n  .footer h5 {\r\n    color: #fff;\r\n    font-size: 0.78rem;\r\n    font-weight: 700;\r\n    letter-spacing: 0.16em;\r\n    margin-bottom: 16px;\r\n    text-transform: uppercase;\r\n  }\r\n  .footer ul { list-style: none; padding: 0; margin: 0; display: flex; flex-direction: column; gap: 10px; }\r\n  .footer ul a:hover { color: var(--green-bright); }\r\n  .footer-bottom {\r\n    border-top: 1px solid rgba(255,255,255,0.12);\r\n    padding-top: 18px;\r\n    display: flex; justify-content: space-between; align-items: center;\r\n    font-size: 0.82rem; color: rgba(255,255,255,0.7);\r\n  }\r\n  .footer-bottom .links { display: flex; gap: 28px; }\r\n\r\n  /* ---------------- RESPONSIVE ---------------- */\r\n  @media (max-width: 1080px) {\r\n    .nav-links { display: none; }\r\n    .hero-inner { grid-template-columns: 1fr; }\r\n    .device-stage { height: 480px; margin-top: 20px; max-width: 600px; }\r\n    .tablet { left: 0; width: 100%; max-width: 580px; }\r\n    .phone { right: 0; }\r\n    .tools-grid { grid-template-columns: repeat(3, 1fr); }\r\n    .tool-cell:nth-child(3) { border-right: 0; }\r\n    .tool-cell:nth-child(n+4) { border-top: 1px solid var(--border); }\r\n    .tool-cell:nth-child(5) { border-right: 0; }\r\n    .everything-grid { grid-template-columns: repeat(3, 1fr); }\r\n    .ev-cell:nth-child(3) { border-right: 0; }\r\n    .ev-cell:nth-child(n+4) { border-top: 1px solid var(--border); }\r\n    .ev-cell:nth-child(6) { border-right: 0; }\r\n    .solutions-card { grid-template-columns: 1fr; padding: 36px; }\r\n    .testimonial-card { grid-template-columns: 1fr; padding: 36px; }\r\n    .testimonial-photo { height: 280px; }\r\n    .stats-overlay { position: static; transform: none; margin-top: 20px; }\r\n    .advantage-inner { grid-template-columns: 1fr; }\r\n    .advantage-badges { justify-content: flex-start; }\r\n    .resources-inner { grid-template-columns: 1fr; }\r\n    .resources-grid { grid-template-columns: 1fr; }\r\n    .footer-grid { grid-template-columns: 1fr 1fr; }\r\n    .stats-grid { grid-template-columns: 1fr 1fr; gap: 40px 20px; }\r\n    .stat-big::after { display: none; }\r\n    .cta-card { flex-direction: column; text-align: center; }\r\n  }\r\n  @media (max-width: 640px) {\r\n    .wrap { padding: 0 20px; }\r\n    .tools-grid, .everything-grid { grid-template-columns: 1fr; }\r\n    .tool-cell, .ev-cell { border-right: 0; border-top: 1px solid var(--border); }\r\n    .integ-logos { gap: 18px; }\r\n    .stats-grid { grid-template-columns: 1fr; }\r\n    .hero { padding: 50px 0 60px; }\r\n    .device-stage { height: auto; min-height: 580px; }\r\n    .tablet { width: 100%; max-width: 460px; height: 320px; left: 0; }\r\n    .phone { width: 130px; height: 260px; right: 0; }\r\n    .footer-grid { grid-template-columns: 1fr; gap: 30px; }\r\n    .footer-bottom { flex-direction: column; gap: 12px; }\r\n  }\nbody.flex { display: block; }\nbody > div { width: 100%; }";

